import{_ as a,c as n,o as s,ae as t}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"Étape 4.2 — Assembler le Header global dans Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/global-header.md","filePath":"drupal-canvas/global-header.md"}'),o={name:"drupal-canvas/global-header.md"};function l(r,e,i,p,u,d){return s(),n("div",null,e[0]||(e[0]=[t(`<h1 id="etape-4-2-—-assembler-le-header-global-dans-canvas" tabindex="-1">Étape 4.2 — Assembler le Header global dans Canvas <a class="header-anchor" href="#etape-4-2-—-assembler-le-header-global-dans-canvas" aria-label="Permalink to &quot;Étape 4.2 — Assembler le Header global dans Canvas&quot;">​</a></h1><h2 id="qu-est-ce-qu-un-global-component" tabindex="-1">Qu&#39;est-ce qu&#39;un Global Component ? <a class="header-anchor" href="#qu-est-ce-qu-un-global-component" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;un Global Component ?&quot;">​</a></h2><p>Un <strong>Global Component</strong> est une zone Canvas partagée sur <strong>toutes les Canvas Pages</strong> du site. Contrairement aux composants que vous placez sur une page spécifique, ce que vous configurez dans un Global Component apparaît partout.</p><p>Le <strong>Header</strong> est le Global Component le plus important : il contient votre navigation, votre logo, et éventuellement une barre de recherche.</p><h2 id="acceder-aux-global-components" tabindex="-1">Accéder aux Global Components <a class="header-anchor" href="#acceder-aux-global-components" aria-label="Permalink to &quot;Accéder aux Global Components&quot;">​</a></h2><p>Dans l&#39;administration Drupal :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Canvas → Global Components → Header</span></span></code></pre></div><p>Ou depuis n&#39;importe quelle Canvas Page, cliquez sur la zone Header en haut de l&#39;éditeur.</p><h2 id="assembler-le-header" tabindex="-1">Assembler le Header <a class="header-anchor" href="#assembler-le-header" aria-label="Permalink to &quot;Assembler le Header&quot;">​</a></h2><h3 id="etape-1-—-placer-le-composant-navigation" tabindex="-1">Étape 1 — Placer le composant Navigation <a class="header-anchor" href="#etape-1-—-placer-le-composant-navigation" aria-label="Permalink to &quot;Étape 1 — Placer le composant Navigation&quot;">​</a></h3><ol><li>Ouvrez l&#39;éditeur des <strong>Global Components → Header</strong></li><li>Dans le <strong>panneau de gauche</strong>, recherchez &quot;Navigation&quot;</li><li>Glissez-le dans la zone Header</li></ol><h3 id="etape-2-—-configurer-les-props-du-composant-navigation" tabindex="-1">Étape 2 — Configurer les props du composant Navigation <a class="header-anchor" href="#etape-2-—-configurer-les-props-du-composant-navigation" aria-label="Permalink to &quot;Étape 2 — Configurer les props du composant Navigation&quot;">​</a></h3><p>Dans le <strong>panneau de droite</strong>, renseignez :</p><table tabindex="0"><thead><tr><th>Prop</th><th>Valeur exemple</th></tr></thead><tbody><tr><td>URL du logo</td><td><code>/themes/custom/mon_theme/logo.svg</code></td></tr><tr><td>Alt du logo</td><td><code>Mon site – Retour à l&#39;accueil</code></td></tr><tr><td>Nom du site</td><td><code>Mon Site</code> (si pas de logo)</td></tr><tr><td>Navigation sticky</td><td>Oui (recommandé)</td></tr></tbody></table><h3 id="etape-3-—-injecter-le-menu-drupal-dans-le-slot" tabindex="-1">Étape 3 — Injecter le menu Drupal dans le slot <a class="header-anchor" href="#etape-3-—-injecter-le-menu-drupal-dans-le-slot" aria-label="Permalink to &quot;Étape 3 — Injecter le menu Drupal dans le slot&quot;">​</a></h3><p>Le slot <strong>Menu principal</strong> attend un bloc Drupal. Pour l&#39;injecter :</p><ol><li>Dans le panneau de gauche, passez sur l&#39;onglet <strong>Blocs</strong></li><li>Recherchez &quot;Main navigation&quot; (ou le nom de votre menu)</li><li>Glissez ce bloc dans le slot <strong>Menu principal</strong> du composant Navigation</li></ol><div class="info custom-block"><p class="custom-block-title">Créer un menu dans Drupal</p><p>Si vous n&#39;avez pas encore de menu, créez-en un dans : <code>Administration → Structure → Menus → Ajouter un menu</code></p><p>Puis ajoutez-y des liens : <code>Administration → Structure → Menus → [Votre menu] → Ajouter un lien</code></p></div><h3 id="etape-4-—-ajouter-une-barre-de-recherche-optionnel" tabindex="-1">Étape 4 — Ajouter une barre de recherche (optionnel) <a class="header-anchor" href="#etape-4-—-ajouter-une-barre-de-recherche-optionnel" aria-label="Permalink to &quot;Étape 4 — Ajouter une barre de recherche (optionnel)&quot;">​</a></h3><p>Si vous souhaitez ajouter une recherche dans le header :</p><ol><li>Activez le module <strong>Search</strong> de Drupal : <code>drush en search</code></li><li>Dans l&#39;éditeur Header, ajoutez un bloc &quot;Formulaire de recherche&quot; après le composant Navigation</li></ol><h2 id="resultat-attendu" tabindex="-1">Résultat attendu <a class="header-anchor" href="#resultat-attendu" aria-label="Permalink to &quot;Résultat attendu&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  [LOGO]    Accueil   Services   À propos   Contact    [🔍]  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Sur mobile :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│  [LOGO]                 [☰]  │</span></span>
<span class="line"><span>└──────────────────────────────┘</span></span>
<span class="line"><span>   ↓ (menu ouvert)</span></span>
<span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│  Accueil                     │</span></span>
<span class="line"><span>│  Services                    │</span></span>
<span class="line"><span>│  À propos                    │</span></span>
<span class="line"><span>│  Contact                     │</span></span>
<span class="line"><span>└──────────────────────────────┘</span></span></code></pre></div><h2 id="sauvegarder-le-header-global" tabindex="-1">Sauvegarder le Header global <a class="header-anchor" href="#sauvegarder-le-header-global" aria-label="Permalink to &quot;Sauvegarder le Header global&quot;">​</a></h2><p>Cliquez sur <strong>Sauvegarder</strong> dans la barre d&#39;outils de Canvas. Le Header est maintenant appliqué à toutes vos Canvas Pages.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>La sauvegarde d&#39;un Global Component <strong>met immédiatement à jour toutes les pages</strong> du site. Vérifiez bien votre configuration avant de sauvegarder.</p></div><h2 id="verifier-sur-plusieurs-pages" tabindex="-1">Vérifier sur plusieurs pages <a class="header-anchor" href="#verifier-sur-plusieurs-pages" aria-label="Permalink to &quot;Vérifier sur plusieurs pages&quot;">​</a></h2><p>Créez ou ouvrez deux Canvas Pages différentes. Le Header doit être identique sur les deux. Si vous modifiez le Header depuis n&#39;importe laquelle de ces pages, le changement s&#39;applique à toutes.</p>`,30)]))}const g=a(o,[["render",l]]);export{h as __pageData,g as default};
